```php
<?php
function isPerfectSquare($num) {
    // Input validation: Ensure the number is positive and an integer
    if (!is_numeric($num) || intval($num) != $num || $num < 0) {
        return "Invalid input! Please enter a non-negative integer.";
    }

    // Calculate the square root
    $sqrt = sqrt($num);

    // Check if the square root is an integer
    if (floor($sqrt) == $sqrt) {
        return "Yay! {$num} is a perfect square.";
    } else {
        return "{$num} is not a perfect square.";
    }
}

// Example usage:
echo isPerfectSquare(16); // Should output: Yay! 16 is a perfect square.
echo "\n";
echo isPerfectSquare(25); // Should output: Yay! 25 is a perfect square.
echo "\n";
echo isPerfectSquare(-4); // Should output: Invalid input! Please enter a non-negative integer.
echo "\n";
echo isPerfectSquare(14); // Should output: 14 is not a perfect square.
?>
```

